"""Cross-era analog fixture (T1; design doc Sec 6.3).

30 hand-built analog pairs — episodes a millennium or an ocean apart that
share a story-shape — plus distractors from the same eras with different
shapes. The gate: each pair member must rank its partner in the top-k
structural neighbors. Until this passes, there is no evidence the
place-blind structural embedding (the system's core bet) works at all.

Failure BLOCKS embedding-model and render-template upgrades (Sec 6.3).

Authoring notes:
- Each pair side is phrased independently (different words, same shape) so
  the fixture measures structural matching, not string overlap.
- BC-era episodes carry no dates (datetime can't express them); the render
  is date-blind anyway.
- Epistemic caveat (Sec 3.2.1): this fixture was authored with LLM
  assistance and shares the canon's priors. Human review before trusting
  it as a gate is part of the ticket's acceptance.
"""

from __future__ import annotations

from datetime import datetime, timezone
from typing import List, Optional, Tuple

from narrative_engine.models import Actor, ArcPhase, ArcType, Episode, MechanismTag

FIXTURE_VERSION = "analog-fixture-v0.1.0"

UTC = timezone.utc
M = MechanismTag


def ep(
    title: str,
    summary: str,
    scope: Optional[str],
    year: Optional[int],
    arc: ArcType,
    phase: ArcPhase,
    roles: List[Tuple[str, str]],
    mechanisms: List[MechanismTag],
    conditions: List[str],
    mechanics: List[str],
    tension: str,
) -> Episode:
    return Episode(
        title=title,
        summary=summary,
        scope_id=scope,
        start_date=datetime(year, 1, 1, tzinfo=UTC) if year else None,
        arc_type=arc,
        arc_phase=phase,
        phase_confidence=0.9,
        actors=[
            Actor(name=name, role=role, canonical_role=role, role_fit_confidence=0.9)
            for name, role in roles
        ],
        mechanism_tags=mechanisms,
        initiating_conditions=conditions,
        escalation_mechanics=mechanics,
        tension=tension,
    )


